namespace sv_307de30e9f574130a365eb2f04dec708.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return the same slots regardless of doctor/date
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    /// <summary>
    /// Validates patient and appointment data against server-side business rules.
    /// Returns a dictionary of field name -> error message for any failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(BookAppointmentModel.Email)] = "Account has outstanding balance";
        }

        // Self-pay patients cannot see Dr. Smith
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(BookAppointmentModel.Doctor)] =
                "Selected doctor does not accept self-pay patients";
        }

        // Simulate race condition on the 10:00 AM slot
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(BookAppointmentModel.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

public class BookAppointmentModel
{
    public string Email { get; set; } = string.Empty;
    public string Doctor { get; set; } = string.Empty;
    public string TimeSlot { get; set; } = string.Empty;
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_307de30e9f574130a365eb2f04dec708.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book a Medical Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    @* ───── STEP 1 ───── *@
    <div class="card mb-4">
        <div class="card-header"><strong>Step 1 — Patient Information</strong></div>
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Patient Name</label>
                <InputText class="form-control" @bind-Value="Model.PatientName" />
                <ValidationMessage For="() => Model.PatientName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText class="form-control" @bind-Value="Model.Email" />
                <ValidationMessage For="() => Model.Email" />
                @if (serverErrors.ContainsKey(nameof(Model.Email)))
                {
                    <div class="validation-message">@serverErrors[nameof(Model.Email)]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label">Phone</label>
                <InputText class="form-control" @bind-Value="Model.Phone" />
                <ValidationMessage For="() => Model.Phone" />
            </div>

            <div class="mb-3">
                <label class="form-label">Insurance Provider</label>
                <InputSelect class="form-select" @bind-Value="Model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option>Aetna</option>
                    <option>BlueCross</option>
                    <option>Cigna</option>
                    <option>UnitedHealth</option>
                    <option>None</option>
                </InputSelect>
                <ValidationMessage For="() => Model.InsuranceProvider" />
            </div>
        </div>
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next: Choose Appointment
        </button>
    }

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <div class="card mb-4">
            <div class="card-header"><strong>Step 2 — Appointment Details</strong></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Preferred Doctor</label>
                    <InputSelect class="form-select" @bind-Value="Model.Doctor"
                                 @bind-Value:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc">@doc</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.Doctor" />
                    @if (serverErrors.ContainsKey(nameof(Model.Doctor)))
                    {
                        <div class="validation-message">@serverErrors[nameof(Model.Doctor)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Date</label>
                    <InputDate class="form-control" @bind-Value="Model.AppointmentDate"
                               @bind-Value:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => Model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Time Slot</label>
                    <InputSelect class="form-select" @bind-Value="Model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in timeSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.TimeSlot" />
                    @if (serverErrors.ContainsKey(nameof(Model.TimeSlot)))
                    {
                        <div class="validation-message">@serverErrors[nameof(Model.TimeSlot)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Reason for Visit</label>
                    <InputTextArea class="form-control" @bind-Value="Model.Reason" rows="3" />
                    <ValidationMessage For="() => Model.Reason" />
                </div>
            </div>
        </div>

        <button type="button" class="btn btn-outline-secondary me-2" @onclick="BackToStep1">
            Back
        </button>
        <button type="button" class="btn btn-primary me-2" @onclick="CheckAvailability"
                disabled="@isChecking">
            @(isChecking ? "Checking…" : "Check Availability")
        </button>

        @if (availabilityConfirmed)
        {
            <button type="submit" class="btn btn-success">Confirm Appointment</button>
        }
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully for <strong>@Model.PatientName</strong>
        with <strong>@Model.Doctor</strong> on @Model.AppointmentDate?.ToString("d")
        at @Model.TimeSlot.
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();
    private EditContext? editContext;

    private bool showStep2;
    private bool isChecking;
    private bool availabilityConfirmed;
    private bool submitted;

    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        var validationMessageStore = new ValidationMessageStore(editContext);

        // Validate only step-1 fields
        bool valid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            validationMessageStore.Add(() => Model.PatientName, "Patient name is required.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            validationMessageStore.Add(() => Model.Email, "Email is required.");
            valid = false;
        }
        else if (!System.Text.RegularExpressions.Regex.IsMatch(
            Model.Email, @"^[^@\s]+@[^@\s]+\.[^@\s]+$"))
        {
            validationMessageStore.Add(() => Model.Email, "Enter a valid email address.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            validationMessageStore.Add(() => Model.Phone, "Phone number is required.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            validationMessageStore.Add(() => Model.InsuranceProvider, "Insurance provider is required.");
            valid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (valid)
        {
            showStep2 = true;
            serverErrors.Clear();
            availabilityConfirmed = false;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
            // Clear selection when slots refresh
            Model.TimeSlot = string.Empty;
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityConfirmed = false;

        // Client-side validation of step-2 fields
        editContext = new EditContext(Model);
        var store = new ValidationMessageStore(editContext);
        bool valid = true;

        if (string.IsNullOrWhiteSpace(Model.Doctor))
        {
            store.Add(() => Model.Doctor, "Please select a doctor.");
            valid = false;
        }
        if (!Model.AppointmentDate.HasValue)
        {
            store.Add(() => Model.AppointmentDate, "Date is required.");
            valid = false;
        }
        else if (Model.AppointmentDate.Value.Date <= DateTime.Today)
        {
            store.Add(() => Model.AppointmentDate, "Date must be in the future.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
        {
            store.Add(() => Model.TimeSlot, "Please select a time slot.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Reason))
        {
            store.Add(() => Model.Reason, "Reason for visit is required.");
            valid = false;
        }
        else if (Model.Reason.Length > 500)
        {
            store.Add(() => Model.Reason, "Reason must be 500 characters or fewer.");
            valid = false;
        }

        editContext.NotifyValidationStateChanged();
        if (!valid) return;

        // Server-side validation
        isChecking = true;
        try
        {
            serverErrors = await AppointmentSvc.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor,
                Model.TimeSlot);

            if (serverErrors.Count == 0)
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        availabilityConfirmed = false;
        editContext = new EditContext(Model);
    }

    private void HandleSubmit()
    {
        if (availabilityConfirmed)
        {
            submitted = true;
        }
    }

    // View-model for the form — keeps validation attributes out of the service layer
    public class AppointmentFormModel
    {
        public string PatientName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
        public string InsuranceProvider { get; set; } = string.Empty;
        public string Doctor { get; set; } = string.Empty;
        public DateTime? AppointmentDate { get; set; }
        public string TimeSlot { get; set; } = string.Empty;
        public string Reason { get; set; } = string.Empty;
    }
}

