+            validationMessageStore.Add(() => Model.Phone, "Phone number is required.");
+            valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
+        {
+            validationMessageStore.Add(() => Model.InsuranceProvider, "Insurance provider is required.");
+            valid = false;
+        }
+
+        editContext.NotifyValidationStateChanged();
+
+        if (valid)
+        {
+            showStep2 = true;
+            serverErrors.Clear();
+            availabilityConfirmed = false;
+        }
+    }
+
+    private async Task OnDoctorOrDateChanged()
+    {
+        availabilityConfirmed = false;
+        serverErrors.Clear();
+
+        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
+        {
+            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
+                Model.Doctor,
+                DateOnly.FromDateTime(Model.AppointmentDate.Value));
+            // Clear selection when slots refresh
+            Model.TimeSlot = string.Empty;
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        serverErrors.Clear();
+        availabilityConfirmed = false;
+
+        // Client-side validation of step-2 fields
+        editContext = new EditContext(Model);
+        var store = new ValidationMessageStore(editContext);
+        bool valid = true;
+
+        if (string.IsNullOrWhiteSpace(Model.Doctor))
+        {
+            store.Add(() => Model.Doctor, "Please select a doctor.");
+            valid = false;
+        }
+        if (!Model.AppointmentDate.HasValue)
+        {
+            store.Add(() => Model.AppointmentDate, "Date is required.");
+            valid = false;
+        }
+        else if (Model.AppointmentDate.Value.Date <= DateTime.Today)
+        {
+            store.Add(() => Model.AppointmentDate, "Date must be in the future.");
+            valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
+        {
+            store.Add(() => Model.TimeSlot, "Please select a time slot.");
+            valid = false;
+        }
+        if (string.IsNullOrWhiteSpace(Model.Reason))
+        {
+            store.Add(() => Model.Reason, "Reason for visit is required.");
+            valid = false;
+        }
+        else if (Model.Reason.Length > 500)
+        {
+            store.Add(() => Model.Reason, "Reason must be 500 characters or fewer.");
+            valid = false;
+        }
+
+        editContext.NotifyValidationStateChanged();
+        if (!valid) return;
+
+        // Server-side validation
+        isChecking = true;
+        try
+        {
+            serverErrors = await AppointmentSvc.ValidatePatientAsync(
+                Model.Email,
+                Model.InsuranceProvider,
+                Model.Doctor,
+                Model.TimeSlot);
+
+            if (serverErrors.Count == 0)
+            {
+                availabilityConfirmed = true;
+            }
+        }
+        finally
+        {
+            isChecking = false;
+        }
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+        serverErrors.Clear();
+        availabilityConfirmed = false;
+        editContext = new EditContext(Model);
+    }
+
+    private void HandleSubmit()
+    {
+        if (availabilityConfirmed)
+        {
+            submitted = true;
+        }
+    }
+
+    // View-model for the form — keeps validation attributes out of the service layer
+    public class AppointmentFormModel
+    {
+        public string PatientName { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+        public string InsuranceProvider { get; set; } = string.Empty;
+        public string Doctor { get; set; } = string.Empty;
+        public DateTime? AppointmentDate { get; set; }
+        public string TimeSlot { get; set; } = string.Empty;
+        public string Reason { get; set; } = string.Empty;
+    }
+}
